from lxml import etree
import io

def process_soap_request(xml_content):
    # Create a secure parser with DTD validation disabled
    parser = etree.XMLParser(
        dtdvalid=False,  # Disable DTD validation to prevent XXE
        load_dtd=False,  # Don't load DTDs
        no_network=True, # Disable network access
        resolve_entities=False, # Don't resolve entities
        suppress_warnings=True,
        recover=True
    )
    
    try:
        # Parse the XML content
        root = etree.fromstring(xml_content.encode('utf-8'), parser)
        
        # Find the SOAP envelope and body
        soap_envelope = root.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Envelope')
        if soap_envelope is None:
            raise ValueError("Invalid SOAP envelope")
            
        soap_body = soap_envelope.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Body')
        if soap_body is None:
            raise ValueError("SOAP body not found")
            
        # Extract the message content
        message_content = []
        for child in soap_body:
            message_content.append(etree.tostring(child, encoding='unicode', pretty_print=True))
            
        return ''.join(message_content)
        
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Invalid XML: {str(e)}")
    except Exception as e:
        raise ValueError(f"Error processing SOAP request: {str(e)}")

